//! Standalone E_8 / Leech vs scalar residual-energy measurement on a REAL FLUX
//! weight tile. Reads ONE Q8_0 weight slab from the knot (a small file-range
//! read — does NOT mmap the whole 17 GB), dequantizes it, and reports cube vs
//! E_8 (8-D) vs Leech (24-D) residual energy at matched cell volume / equal bit
//! budget. Honest: if the lattice does NOT beat the cube on real FLUX weights,
//! it is reported plainly.
//!
//! usage: flux-lattice-dump <knot> [tensor_name]
//!   default tensor: flux_dbl_0_img_fc1_weight (12288 x 3072 Q8_0)

use distributed_inference::flux_lattice_residual::measure_flux_q8_tile_lattice;
use distributed_inference::loader::{fetch_knot_tensor_bytes_from_metadata, KnotWeights};

const DEFAULT_TENSOR: &str = "flux_dbl_0_img_fc1_weight";

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        eprintln!("usage: flux-lattice-dump <knot> [tensor_name]");
        std::process::exit(2);
    }
    let knot_path = &args[1];
    let tensor = args.get(2).map(|s| s.as_str()).unwrap_or(DEFAULT_TENSOR);

    let knot = KnotWeights::load_metadata_only(knot_path).expect("load knot metadata");
    let info = knot
        .metadata
        .get(tensor)
        .unwrap_or_else(|| panic!("tensor {tensor} not in knot metadata"))
        .clone();

    eprintln!(
        "tensor {tensor}: type={} shape={:?} length={} bytes",
        info.tensor_type, info.shape, info.length
    );
    if !info.tensor_type.eq_ignore_ascii_case("Q8_0") {
        eprintln!(
            "WARNING: tensor is {} not Q8_0 — measurement assumes Q8_0 block layout",
            info.tensor_type
        );
    }

    let fetched = fetch_knot_tensor_bytes_from_metadata(
        knot_path,
        &knot.metadata,
        knot.payload_offset,
        tensor,
    )
    .expect("fetch tensor bytes");

    let total = info
        .shape
        .as_ref()
        .map(|s| s.iter().product::<usize>())
        .unwrap_or((fetched.bytes.len() / 34) * 32);

    eprintln!(
        "dequantizing {} Q8_0 bytes -> {} f32 weights",
        fetched.bytes.len(),
        total
    );

    let rep = measure_flux_q8_tile_lattice(&fetched.bytes, total);

    println!("=== REAL FLUX TILE LATTICE RESIDUAL ENERGY ===");
    println!("tensor: {tensor}");
    println!("E8  tiles (8-D):  {}", rep.e8_tiles);
    println!("Leech tiles (24-D): {}", rep.leech_tiles);
    println!();
    println!(
        "E8:    scalar {:.6e}   lattice {:.6e}   reduction {:+.2}%  (positive = lattice wins)",
        rep.scalar_e8_energy,
        rep.e8_energy,
        100.0 * rep.e8_reduction()
    );
    println!(
        "Leech: scalar {:.6e}   lattice {:.6e}   reduction {:+.2}%  (positive = lattice wins)",
        rep.scalar_leech_energy,
        rep.leech_energy,
        100.0 * rep.leech_reduction()
    );
    println!();
    println!(
        "VERDICT: lattice_is_superior = {}  (both E8 AND Leech strictly beat scalar)",
        rep.lattice_is_superior()
    );
    println!(
        "  E8 beats scalar:    {}",
        rep.e8_energy < rep.scalar_e8_energy
    );
    println!(
        "  Leech beats scalar: {}",
        rep.leech_energy < rep.scalar_leech_energy
    );
}
